import React from 'react';
import { ChevronLeft, Plus } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

export default function GoalsScreen({ goals, onBack, onGoalSelect, onAddGoal }) {
  const { formatAmount } = useCurrency();

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-bottom duration-500">
      {/* Header */}
      <div className="flex items-center px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900 ml-4">My Goals</h1>
      </div>

      {/* Goal List */}
      <div className="p-6 flex-1 overflow-y-auto scrollbar-hide space-y-4">
        {goals.map((goal, i) => (
          <div 
            key={i} 
            className="p-5 bg-gray-50 rounded-[2rem] border border-gray-100 cursor-pointer"
            onClick={() => onGoalSelect(goal)}
          >
            <p className="text-sm font-black text-gray-900">{goal.title}</p>
            <p className="text-xs text-gray-500 mt-1">{formatAmount(goal.current)} / {formatAmount(goal.target)}</p>
          </div>
        ))}

        {/* Add Goal Button */}
        <button 
          onClick={onAddGoal}
          className="w-full py-4 mt-4 rounded-2xl font-black text-white bg-[#00875A] shadow-lg flex items-center justify-center gap-3 active:scale-[0.98] transition-all"
        >
          <Plus size={20} /> Add New Goal
        </button>
      </div>
    </div>
  );
}
